import React, { useEffect } from "react";
import "../styles/Contact.css";

const Contact = () => {
  useEffect(() => {
    // Dynamically load the Google Maps script
    const script = document.createElement("script");
    script.src = "https://maps.googleapis.com/maps/api/js?key=YOUR_GOOGLE_MAPS_API_KEY&libraries=maps&v=beta";
    script.defer = true;
    document.body.appendChild(script);

    // Initialize the map after the script is loaded
    script.onload = () => {
      const { Map } = window.google.maps; // Access the Google Maps API
      const map = new Map(document.getElementById("map"), {
        center: { lat: 40.183666, lng: 44.629132 },
        zoom: 15,
      });
    };
  }, []);

  return (
    <div id="contact" className="contact-container">
      <h1>CONTACT US</h1>

      {/* Google Maps Section */}
      <div className="map-container" id="map" style={{ height: "400px", width: "100%" }}></div>

      <div className="contact-content">
        <div className="contact-info">
          <h2>Law Office</h2>
          <div className="info-item">
            <span className="icon">📍</span>
            <div>
              <h3>Address</h3>
              <p>ITS Tower - Nifarro Park 8th Floor, Unit 801, 802, 817</p>
              <p>Jl. K.H. Guru Amin (F.K.A: Jl. Raya Pasar Minggu) No. 18</p>
              <p>Jakarta Selatan 12510, Indonesia</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📞</span>
            <div>
              <h3>Phone</h3>
              <p>+374 12 34 56 78</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📧</span>
            <div>
              <h3>E-mail</h3>
              <p>info@law.com</p>
            </div>
          </div>
        </div>

        <div className="contact-form">
          <h3>LEAVE US A MESSAGE</h3>
          <form>
            <input type="text" placeholder="Your Full Name" required />
            <input type="email" placeholder="example@email.com" required />
            <input type="text" placeholder="012 34 56 78" required />
            <input type="text" placeholder="Subject" required />
            <textarea placeholder="Write your message here..." required></textarea>
            <div className="recaptcha">
              <img
                src="https://www.gstatic.com/recaptcha/api2/logo_48.png"
                alt="reCAPTCHA"
              />
              <span>protected by reCAPTCHA</span>
            </div>
            <button type="submit">Submit</button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Contact;
